B.a34=new A.m(B.j,["In Your name, O Allah, I die and I live.","\u0628\u0627\u0633\u0645\u0643 \u0627\u0644\u0644\u0647\u0645 \u0623\u0645\u0648\u062a \u0648\u0623\u062d\u064a\u0627","\u0421 \u0422\u0432\u043e\u0438\u043c \u0438\u043c\u0435\u043d\u0435\u043c, \u043e \u0410\u043b\u043b\u0430\u0445, \u044f \u0443\u043c\u0438\u0440\u0430\u044e \u0438 \u0436\u0438\u0432\u0443.","\u0924\u0947\u0930\u0947 \u0928\u093e\u092e \u0938\u0947, \u0910 \u0905\u0932\u094d\u0932\u093e\u0939, \u092e\u0948\u0902 \u092e\u0930\u0924\u093e \u0914\u0930 \u091c\u0940\u0924\u093e \u0939\u0942\u0901\u0964","Dengan nama-Mu ya Allah, aku mati dan aku hidup.","\u4ee5\u4f60\u7684\u540d\u4e49\uff0c\u771f\u4e3b\u554a\uff0c\u6211\u6b7b\u53bb\u6211\u6d3b\u7740\u3002","In Deinem Namen, o Allah, sterbe und lebe ich.","In Uw naam, o Allah, sterf en leef ik.","En Ton nom, \xf4 Allah, je meurs et je vis.","En Tu nombre, oh Allah, muero y vivo."],t.w)
B.a0o=new A.m(B.cS,["sleep",B.OO,"\u0628\u0650\u0627\u0633\u0652\u0645\u0650\u0643\u064e \u0627\u0644\u0644\u064e\u0651\u0647\u064f\u0645\u064e\u0651 \u0623\u064e\u0645\u064f\u0648\u062a\u064f \u0648\u064e\u0623\u064e\u062d\u0652\u064a\u064e\u0627","Bismika Allahumma amutu wa ahya.",B.a34],t.yf)
