B.a3g=new A.m(B.j,["In the name of Allah and with the blessings of Allah.","\u0628\u0633\u0645 \u0627\u0644\u0644\u0647 \u0648\u0639\u0644\u0649 \u0628\u0631\u0643\u0629 \u0627\u0644\u0644\u0647","\u0412\u043e \u0438\u043c\u044f \u0410\u043b\u043b\u0430\u0445\u0430 \u0438 \u0441 \u0431\u043b\u0430\u0433\u043e\u0441\u043b\u043e\u0432\u0435\u043d\u0438\u0435\u043c \u0410\u043b\u043b\u0430\u0445\u0430.","\u0905\u0932\u094d\u0932\u093e\u0939 \u0915\u0947 \u0928\u093e\u092e \u0938\u0947 \u0914\u0930 \u0905\u0932\u094d\u0932\u093e\u0939 \u0915\u0940 \u092c\u0930\u0915\u0924 \u0938\u0947\u0964","Dengan nama Allah dan dengan berkah Allah.","\u4ee5\u771f\u4e3b\u4e4b\u540d\uff0c\u51ed\u771f\u4e3b\u7684\u5409\u5e86\u3002","Im Namen Allahs und mit dem Segen Allahs.","In de naam van Allah en met de zegeningen van Allah.","Au nom d'Allah et avec les b\xe9n\xe9dictions d'Allah.","En el nombre de Allah y con las bendiciones de Allah."],t.w)
B.a0n=new A.m(B.cS,["food",B.P3,"\u0628\u0650\u0633\u0652\u0645\u0650 \u0627\u0644\u0644\u064e\u0651\u0647\u0650 \u0648\u064e\u0639\u064e\u0644\u064e\u0649 \u0628\u064e\u0631\u064e\u0643\u064e\u0629\u0650 \u0627\u0644\u0644\u064e\u0651\u0647\u0650","Bismillahi wa ala barakatillah.",B.a3g],t.yf)
